<template>
  <div class="infotulovInvoice" v-if="option">
    <div class="invoice_container px-3 py-3">
      <!-- Top Info Cards -->
      <div class="info_cards_row">
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="user" class="card_icon"/>
            <span class="card_label">{{$t('client')}}</span>
          </div>
          <div class="card_value">{{option.text_2 || '-'}}</div>
        </div>
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="box" class="card_icon"/>
            <span class="card_label">{{option.text_1 || $t('product')}}</span>
          </div>
          <div class="card_value">{{formatNumber(option.product_measure)}} кг</div>
        </div>
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="dollar-sign" class="card_icon"/>
            <span class="card_label">{{$t('product_price')}}</span>
          </div>
          <div class="card_value">
            <span v-if="option.payed_summ && option.dolg_summ">
              {{ formatNumber(option.payed_summ/option.dolg_summ) }} сўм
            </span>
            <span v-else>
              {{formatNumber(option.product_price)}} сўм
            </span>
          </div>
        </div>
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="wallet" class="card_icon"/>
            <span class="card_label">{{$t('ostatka')}}</span>
          </div>
          <div class="card_value">{{formatNumber(option.credit_sum)}} сўм</div>
        </div>
      </div>

      <!-- Main Content Row -->
      <div class="main_content_row">
        <!-- Left Side: Payment Info & Image -->
        <div class="left_sidebar">
          <div class="payment_info_card">
            <div class="payment_header">
              <h6 class="payment_title">{{option.text_1}}</h6>
              <span class="payment_measure">{{formatNumber(option.dolg_summ)}} кг</span>
            </div>
            <div class="payment_amount">
              <span class="amount_value">{{formatNumberWithSpaces(option.payed_summ)}}</span>
              <span class="amount_currency">сўм</span>
            </div>
          </div>
          <div class="image_card">
            <div class="image_wrapper">
              <img 
                v-if="option.image_last_pull" 
                :src="hostname + option.image_last_pull" 
                alt="Invoice image"
                class="invoice_image"
              />
              <div v-else class="image_placeholder">
                <mdb-icon icon="camera" size="3x" class="placeholder_icon"/>
                <p class="placeholder_text">Rasm yo'q</p>
              </div>
            </div>
          </div>
        </div>

        <!-- Right Side: Product List -->
        <div class="right_content">
          <div class="product_info_card">
            <div class="product_header">
              <h6 class="product_title">{{option.text_1}}</h6>
              <span class="product_measure_badge">
                {{formatNumber(option.product_measure - option.dolg_summ)}} кг
              </span>
            </div>
            <div class="table_wrapper">
              <table class="product_table">
                <thead>
                  <tr class="table_header">
                    <th width="50" class="text-center">№</th>
                    <th>{{$t('product')}}</th>
                    <th>{{$t('measure')}}</th>
                    <th>Исполь. масса</th>
                    <th>Основные продукты</th>
                  </tr>
                </thead>
                <tbody>
                  <tr v-for="(row,i) in option.item_list" :key="i" class="table_row">
                    <td class="text-center">
                      <span class="row_number">{{i+1}}</span>
                    </td>
                    <td>
                      <span class="product_name">{{row.product.name}}</span>
                    </td>
                    <td>
                      <span class="measure_value">{{row.qty}}</span>
                    </td>
                    <td>
                      <span class="measure_value">{{formatNumber(parseFloat(row.qty)/parseFloat(row.real_sum))}}</span>
                    </td>
                    <td>
                      <span class="product_name">{{option.text_1}}</span>
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>

      <!-- Footer Info -->
      <div class="footer_info">
        <div class="footer_card">
          <div class="footer_row">
            <span class="footer_label">
              <mdb-icon icon="user-tie" class="mr-1"/>
              Кассир
            </span>
            <span class="footer_value">{{option.auth_last_pull_name || '-'}}</span>
          </div>
          <div class="footer_row">
            <span class="footer_label">
              <mdb-icon icon="calendar" class="mr-1"/>
              {{$t('date')}}
            </span>
            <span class="footer_value">
              <span>{{formatDate(option.date_last_pull)}}</span>
              <span class="ml-2">{{formatTime(option.date_last_pull)}}</span>
            </span>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import {mdbBtn, mdbIcon} from 'mdbvue'
export default {
  components:{
    mdbBtn, mdbIcon
  },
  data() {
    return {
      hostname: this.$store.state.server_ip,
    }
  },
props:{
  option:{
    type: Object,
    default() {
      return {}
    }
  }
},
methods:{
  printInfo(){
    this.$emit('printed', this.option)
  },
  formatNumber(num) {
    if (typeof num !== 'number' && typeof num !== 'string') return '0';
    if (num === null || num === undefined || isNaN(num)) return '0';
    return parseFloat(num).toFixed(1);
  },
  formatNumberWithSpaces(num) {
    if (num === null || num === undefined || num === '') return '0';
    const numStr = typeof num === 'string' ? num : num.toString();
    return numStr.replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
  },
  formatDate(dateString) {
    if (!dateString || typeof dateString !== 'string') return '-';
    if (dateString.length < 10) return '-';
    return dateString.slice(8,10) + '-' + dateString.slice(5,7) + '-' + dateString.slice(0,4);
  },
  formatTime(dateString) {
    if (!dateString || typeof dateString !== 'string') return '-';
    if (dateString.length < 16) return '-';
    return dateString.slice(11,16);
  }
}
}
</script>

<style lang="scss" scoped>
.infotulovInvoice {
  background: #F1F4F5;
  // min-height: 100vh;
  padding: 16px 0;
}

