  padding: 20px;
  box-shadow: 0 4px 12px rgba(163, 203, 213, 0.3);

  .payment_header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 16px;
    padding-bottom: 12px;
    border-bottom: 2px solid rgba(255, 255, 255, 0.3);

    .payment_title {
      color: white;
      font-size: 16px;
      font-weight: 600;
      margin: 0;
    }

    .payment_measure {
      color: white;
      font-size: 14px;
      font-weight: 600;
