      gap: 12px;
      color: #597e8d;
      padding: 40px;

      .placeholder_icon {
        opacity: 0.5;
      }

      .placeholder_text {
        margin: 0;
        font-size: 14px;
        font-weight: 500;
      }
    }
  }
}

.right_content {
  .product_info_card {
    background: white;
    border-radius: 12px;
    padding: 20px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
    height: 100%;

    .product_header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 16px;
      padding-bottom: 12px;
      border-bottom: 2px solid #f0f0f0;

      .product_title {
        color: #2c3e50;
        font-size: 16px;
        font-weight: 600;
        margin: 0;
      }

      .product_measure_badge {
        background: linear-gradient(135deg, #A3CBD5 0%, #456F8E 100%);
        color: white;
        padding: 6px 14px;
        border-radius: 20px;
        font-size: 13px;
        font-weight: 600;
      }
    }
  }
}

.table_wrapper {
  max-height: 400px;
  overflow-y: auto;
  border-radius: 8px;
}

.product_table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;

  .table_header {
    background: linear-gradient(135deg, #A3CBD5 0%, #456F8E 100%);
