    top: 0;
    z-index: 10;

    th {
      padding: 10px 14px;
      font-weight: 600;
      font-size: 11px;
      text-transform: uppercase;
      letter-spacing: 0.5px;
      text-align: left;

      &:first-child {
        border-top-left-radius: 8px;
      }
      &:last-child {
        border-top-right-radius: 8px;
      }
    }
  }

  .table_row {
    border-bottom: 1px solid #f0f0f0;
    transition: all 0.2s ease;

    &:hover {
      background: linear-gradient(90deg, rgba(163, 203, 213, 0.1) 0%, rgba(69, 111, 142, 0.05) 100%);
    }

    &:last-child {
