  .footer_row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 0;

    &:not(:last-child) {
      border-bottom: 1px solid #f0f0f0;
    }

    .footer_label {
      display: flex;
      align-items: center;
      font-size: 13px;
