<template>
  <div class="infotulovInvoice" v-if="option">
    <div class="invoice_container px-3 py-3">
      <!-- Top Info Cards -->
      <div class="info_cards_row">
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="ruler" class="card_icon"/>
            <span class="card_label">{{$t('all_measure')}}</span>
          </div>
          <div class="card_value">{{formatNumber(option.all_measure)}}</div>
        </div>
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="truck" class="card_icon"/>
            <span class="card_label">{{$t('car_measure')}}</span>
          </div>
          <div class="card_value">{{formatNumber(option.car_measure)}} кг</div>
        </div>
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="percent" class="card_icon"/>
            <span class="card_label">{{$t('discount')}}</span>
          </div>
          <div class="card_value">{{formatNumber(option.discount)}} кг</div>
        </div>
        <div class="info_card">
          <div class="card_header">
            <mdb-icon icon="box" class="card_icon"/>
            <span class="card_label">{{$t('product_measure')}}</span>
          </div>
          <div class="card_value">{{formatNumber(option.product_measure)}} кг</div>
        </div>
      </div>

      <!-- Client & Product Info -->
      <div class="info_section_row">
        <div class="info_section_card">
          <h6 class="section_title">
            <mdb-icon icon="user" class="mr-2"/>
            {{$t('client_info') || 'Информация о клиенте'}}
          </h6>
          <div class="info_list">
            <div class="info_item">
              <span class="info_label">{{$t('client')}}</span>
              <span class="info_value">{{option.text_2 || '-'}}</span>
            </div>
            <div class="info_item">
              <span class="info_label">{{$t('shafyor_name')}}</span>
              <span class="info_value">{{option.shafyor_name || '-'}}</span>
            </div>
            <div class="info_item">
              <span class="info_label">{{$t('shafyor_tel')}}</span>
              <span class="info_value">{{option.shafyor_tel || '-'}}</span>
            </div>
            <div class="info_item">
              <span class="info_label">{{$t('car_number')}}</span>
              <span class="info_value">{{option.car_number || '-'}}</span>
            </div>
          </div>
        </div>
        <div class="info_section_card">
          <h6 class="section_title">
            <mdb-icon icon="receipt" class="mr-2"/>
            {{$t('product_info') || 'Информация о продукте'}}
          </h6>
          <div class="info_list">
            <div class="info_item">
              <span class="info_label">{{$t('product_price')}}</span>
              <span class="info_value price_value">{{formatNumberWithSpaces(option.product_price)}} сўм</span>
            </div>
            <div class="info_item">
              <span class="info_label">{{$t('summ')}}</span>
              <span class="info_value price_value">{{formatNumberWithSpaces(option.summ)}} сўм</span>
            </div>
            <div class="info_item">
              <span class="info_label">{{$t('note')}}</span>
              <span class="info_value">{{option.note || '-'}}</span>
            </div>
            <div class="info_item">
              <span class="info_label">{{$t('status')}}</span>
              <span class="status_badge status_qabul">
                <mdb-icon icon="check-circle" class="mr-1"/>
                Qabul qilingan
              </span>
            </div>
          </div>
        </div>
      </div>

      <!-- Images Section -->
      <div class="images_section">
        <h6 class="section_title">
          <mdb-icon icon="images" class="mr-2"/>
          {{$t('images') || 'Изображения'}}
        </h6>
        <div class="images_grid">
          <div class="image_card" v-for="(image, index) in images" :key="index">
            <div class="image_header">
              <span class="image_label">{{image.label}}</span>
            </div>
            <div class="image_wrapper">
              <img 
                v-if="image.src" 
                :src="hostname + image.src" 
                :alt="image.label"
                class="invoice_image"
              />
              <div v-else class="image_placeholder">
                <mdb-icon icon="camera" size="2x" class="placeholder_icon"/>
                <p class="placeholder_text">Rasm yo'q</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Date Info Section -->
      <div class="date_section">
        <h6 class="section_title">
          <mdb-icon icon="clock" class="mr-2"/>
          {{$t('date_info') || 'Дата и время'}}
        </h6>
        <div class="date_cards_row">
          <div class="date_card" v-for="(dateInfo, index) in dateInfoList" :key="index">
            <div class="date_card_header">
              <mdb-icon icon="user-tie" class="date_icon"/>
              <span class="date_label">{{dateInfo.label}}</span>
            </div>
            <div class="date_card_body">
              <div class="cashier_info">
                <span class="cashier_label">Кассир:</span>
                <span class="cashier_value">{{dateInfo.cashier || '-'}}</span>
              </div>
              <div class="date_time_info">
                <span class="date_text">{{formatDate(dateInfo.date)}}</span>
                <span class="time_text">{{formatTime(dateInfo.date)}}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import {mdbBtn, mdbIcon} from 'mdbvue'
export default {
  components:{
    mdbBtn, mdbIcon
  },
  data() {
    return {
      hostname: this.$store.state.server_ip,
    }
  },
  computed: {
    images() {
      return [
        { src: this.option.image_first_pull, label: this.$t('first_pull_image') || 'Первая выгрузка' },
        { src: this.option.image_second_pull, label: this.$t('second_pull_image') || 'Вторая выгрузка' },
        { src: this.option.image_last_pull, label: this.$t('last_pull_image') || 'Последняя выгрузка' }
      ];
    },
    dateInfoList() {
      return [
        { 
          label: this.$t('first_pull_image') || 'Первая выгрузка',
          date: this.option.date_first_pull,
          cashier: this.option.auth_first_pull_name
        },
        { 
          label: this.$t('second_pull_image') || 'Вторая выгрузка',
          date: this.option.date_second_pull,
          cashier: this.option.auth_second_pull_name
        },
        { 
          label: this.$t('last_pull_image') || 'Последняя выгрузка',
          date: this.option.date_last_pull,
          cashier: this.option.auth_last_pull_name
        }
      ];
    }
  },
props:{
  option:{
    type: Object,
    default() {
      return {}
    }
  }
},
methods:{
  printInfo(){
    this.$emit('printed', this.option)
  },
  formatNumber(num) {
    if (typeof num !== 'number' && typeof num !== 'string') return '0';
    if (num === null || num === undefined || isNaN(num)) return '0';
    return parseFloat(num).toFixed(1);
  },
  formatNumberWithSpaces(num) {
    if (num === null || num === undefined || num === '') return '0';
    const numStr = typeof num === 'string' ? num : num.toString();
    return numStr.replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
  },
  formatDate(dateString) {
    if (!dateString || typeof dateString !== 'string') return '-';
    if (dateString.length < 10) return '-';
    return dateString.slice(8,10) + '-' + dateString.slice(5,7) + '-' + dateString.slice(0,4);
  },
  formatTime(dateString) {
    if (!dateString || typeof dateString !== 'string') return '-';
    if (dateString.length < 16) return '-';
    return dateString.slice(11,16);
  }
}
}
</script>

<style lang="scss" scoped>
