  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);

  .section_title {
    display: flex;
    align-items: center;
    color: #2c3e50;
    font-size: 16px;
    font-weight: 600;
    margin: 0 0 16px 0;
    padding-bottom: 12px;
    border-bottom: 2px solid #f0f0f0;
  }

  .info_list {
    display: flex;
    flex-direction: column;
    gap: 12px;
  }

  .info_item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px 0;

    &:not(:last-child) {
      border-bottom: 1px solid #f0f0f0;
    }

    .info_label {
      font-size: 13px;
      font-weight: 500;
      color: #67748E;
    }

    .info_value {
      font-size: 13px;
      font-weight: 600;
      color: #2c3e50;
