  }
}

// Images Section
.images_section {
  background: white;
  border-radius: 12px;
  padding: 20px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  margin-bottom: 20px;

  .section_title {
    display: flex;
    align-items: center;
    color: #2c3e50;
    font-size: 16px;
    font-weight: 600;
