}

// Date Section
.date_section {
  background: white;
  border-radius: 12px;
  padding: 20px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.date_cards_row {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 16px;
  margin-top: 16px;
}

.date_card {
  background: linear-gradient(135deg, rgba(163, 203, 213, 0.1) 0%, rgba(69, 111, 142, 0.05) 100%);
  border-radius: 12px;
  padding: 16px;
  border: 2px solid rgba(163, 203, 213, 0.2);
  transition: all 0.3s ease;

  &:hover {
